INSERT INTO ui_translations (key, locale, value) VALUES
  ('nav.memory_book', 'es', 'Por qué su familia necesita un Libro de Memoria'),
  ('mb_page.eyebrow', 'es', 'Libro de Memoria'),
  ('mb_page.hero_title', 'es', 'Todo lo que un cuidador necesita saber — en un solo lugar'),
  ('mb_page.hero_body', 'es', 'Cuando llega un nuevo cuidador, no debería tener que adivinar. El Libro de Memoria registra quién es su ser querido, a quién llamar, qué observar y qué les brinda comodidad — compartido al instante con todos en su equipo de cuidado.'),
  ('mb_page.hero_cta_primary', 'es', 'Crear su Libro de Memoria'),
  ('mb_page.hero_cta_secondary', 'es', 'Iniciar Sesión'),
  ('mb_page.mock_title', 'es', 'Vea cómo es el Libro de Memoria'),
  ('mb_page.mock_subtitle', 'es', 'Un perfil de cuidado vivo que cada miembro de su equipo puede ver en el momento en que se une.'),
  ('mb_page.mock_book_title', 'es', 'Libro de Memoria'),
  ('mb_page.mock_tab_overview', 'es', 'Resumen'),
  ('mb_page.mock_tab_identity', 'es', 'Identidad'),
  ('mb_page.mock_tab_contacts', 'es', 'Contactos'),
  ('mb_page.mock_tab_medical', 'es', 'Médico'),
  ('mb_page.mock_tab_prefs', 'es', 'Gustos y Disgustos'),
  ('mb_page.mock_identity_heading', 'es', 'Identidad y Perfil'),
  ('mb_page.mock_identity_sub', 'es', 'Datos personales de Margarita H.'),
  ('mb_page.mock_edit_btn', 'es', 'Editar'),
  ('mb_page.mock_field_preferred_name', 'es', 'Nombre Preferido'),
  ('mb_page.mock_field_address', 'es', 'Cómo Dirigirse'),
  ('mb_page.mock_field_birthplace', 'es', 'Lugar de Nacimiento'),
  ('mb_page.mock_field_rel_status', 'es', 'Estado Civil'),
  ('mb_page.mock_field_cultural', 'es', 'Origen Cultural'),
  ('mb_page.mock_field_language', 'es', 'Preferencias de Idioma'),
  ('mb_page.mock_field_about', 'es', 'Sobre Mí'),
  ('mb_page.mock_about_text', 'es', 'Margarita fue maestra de escuela durante 30 años en Edimburgo antes de emigrar con su difunto esposo Santiago. Tiene un sentido del humor cálido y seco, y un profundo amor por los crucigramas, una buena taza de té e historias sobre sus nietos.'),
  ('mb_page.mock_progress_label', 'es', 'Progreso del Libro de Memoria'),
  ('mb_page.mock_sections', 'es', 'secciones completas'),
  ('mb_page.benefits_title', 'es', 'Por qué las familias confían en el Libro de Memoria'),
  ('mb_page.benefits_subtitle', 'es', 'Los equipos de cuidado funcionan mejor cuando todos tienen la misma información desde el primer día.'),
  ('mb_page.benefit1_title', 'es', 'Contexto de cuidado inmediato'),
  ('mb_page.benefit1_body', 'es', 'Cualquier nuevo cuidador — un trabajador de relevo, un hermano de visita desde el extranjero — llega con todo lo que necesita para brindar buena atención desde el primer momento.'),
  ('mb_page.benefit2_title', 'es', 'No más buscar números'),
  ('mb_page.benefit2_body', 'es', 'Cada familiar, médico y contacto de emergencia en un solo lugar. Encuentre a la persona correcta en segundos, no en minutos.'),
  ('mb_page.benefit3_title', 'es', 'Transferencias más seguras'),
  ('mb_page.benefit3_body', 'es', 'Notas médicas, alergias y consideraciones de cuidado siempre a mano. Las transiciones informadas significan menos vacíos y menos riesgos.'),
  ('mb_page.benefit4_title', 'es', 'Dignidad personal'),
  ('mb_page.benefit4_body', 'es', 'Más allá de los datos clínicos, el Libro de Memoria captura a la persona — su historia, sus preferencias, lo que le trae alegría. El cuidado se convierte en más que completar tareas.'),
  ('mb_page.features_title', 'es', 'Cuatro secciones. Una imagen completa.'),
  ('mb_page.features_subtitle', 'es', 'Cada sección está diseñada en torno a momentos reales de cuidado — transferencias, emergencias, nuevos miembros del equipo y cuidado cotidiano.'),
  ('mb_page.feat_identity_title', 'es', 'Identidad y Perfil Personal'),
  ('mb_page.feat_identity_body', 'es', 'Capture quién es su ser querido — no solo su nombre, sino su historia. Esta sección ayuda a cada cuidador a conectarse con la persona detrás del plan de cuidado.'),
  ('mb_page.feat_identity_f1', 'es', 'Nombre preferido y cómo le gusta ser llamado'),
  ('mb_page.feat_identity_f2', 'es', 'Lugar de nacimiento y origen cultural'),
  ('mb_page.feat_identity_f3', 'es', 'Estado civil'),
  ('mb_page.feat_identity_f4', 'es', 'Preferencias de idioma y comunicación'),
  ('mb_page.feat_identity_f5', 'es', 'Resumen personal — en sus propias palabras'),
  ('mb_page.feat_contacts_title', 'es', 'Red de Cuidado y Contactos'),
  ('mb_page.feat_contacts_body', 'es', 'Almacene a cada persona en la red de apoyo de su ser querido — familiares, médicos, especialistas y contactos de emergencia — cada uno con su función, teléfono, correo electrónico y notas.'),
  ('mb_page.feat_contacts_f1', 'es', 'Miembros de la familia y su relación'),
  ('mb_page.feat_contacts_f2', 'es', 'Contactos de médico de cabecera y especialistas'),
  ('mb_page.feat_contacts_f3', 'es', 'Vecinos y apoyo comunitario'),
  ('mb_page.feat_contacts_f4', 'es', 'Etiquetas de función: cuidador principal, emergencia, médico, otro'),
  ('mb_page.feat_medical_title', 'es', 'Contexto Médico'),
  ('mb_page.feat_medical_body', 'es', 'No es un historial clínico — es una referencia práctica para cuidadores. Documente lo que los cuidadores domiciliarios y familiares realmente necesitan saber para brindar una atención segura y confiada.'),
  ('mb_page.feat_medical_f1', 'es', 'Condiciones principales y diagnósticos'),
  ('mb_page.feat_medical_f2', 'es', 'Alergias (alimentarias, medicamentosas, ambientales)'),
  ('mb_page.feat_medical_f3', 'es', 'Notas de audición y visión'),
  ('mb_page.feat_medical_f4', 'es', 'Medicamentos actuales y notas de administración'),
  ('mb_page.feat_medical_f5', 'es', 'Otras consideraciones de salud para cuidadores'),
  ('mb_page.feat_prefs_title', 'es', 'Gustos, Disgustos y Consuelos'),
  ('mb_page.feat_prefs_body', 'es', 'Los detalles que transforman el cuidado de funcional a personal. Saber qué calma, qué evitar y qué provoca una sonrisa genuina hace que cada interacción sea mejor.'),
  ('mb_page.feat_prefs_f1', 'es', 'Actividades, temas y experiencias que disfrutan'),
  ('mb_page.feat_prefs_f2', 'es', 'Preferencias alimentarias y cosas a evitar'),
  ('mb_page.feat_prefs_f3', 'es', 'Preferencias musicales y temas de conversación favoritos'),
  ('mb_page.feat_prefs_f4', 'es', 'Qué les consuela cuando están molestos'),
  ('mb_page.feat_prefs_f5', 'es', 'Preferencias sensoriales y desencadenantes de angustia'),
  ('mb_page.access_title', 'es', 'Creado para el equipo. Visible para todos.'),
  ('mb_page.access_body', 'es', 'El propietario del equipo crea el Libro de Memoria. Cada cuidador que invite — familiares, trabajadores domiciliarios o personas de apoyo — puede verlo en el momento en que se una, sin configuración adicional.'),
  ('mb_page.access_cta', 'es', 'Crear su Cuenta Gratuita'),
  ('mb_page.access_plans', 'es', 'Ver Planes y Precios'),
  ('mb_page.personas_title', 'es', 'Quién se beneficia del Libro de Memoria'),
  ('mb_page.personas_subtitle', 'es', 'Desde el cuidador nocturno que llega por primera vez hasta un hermano que visita desde el extranjero.'),
  ('mb_page.persona1_title', 'es', 'El cuidador de relevo nocturno'),
  ('mb_page.persona1_quote', 'es', '"Antes temía cubrir a una familia que no conocía. Ahora reviso el Libro de Memoria antes de llegar."'),
  ('mb_page.persona1_b1', 'es', 'Conoce las rutinas preferidas y los consuelos antes de entrar'),
  ('mb_page.persona1_b2', 'es', 'Puede encontrar contactos de emergencia sin despertar a nadie'),
  ('mb_page.persona1_b3', 'es', 'Entiende las necesidades de medicación desde la primera noche'),
  ('mb_page.persona2_title', 'es', 'El hermano que regresa del extranjero'),
  ('mb_page.persona2_quote', 'es', '"Visito dos veces al año y me siento como un extraño. El Libro de Memoria cierra esa brecha."'),
  ('mb_page.persona2_b1', 'es', 'Se pone al día con el contexto médico sin un largo repaso familiar'),
  ('mb_page.persona2_b2', 'es', 'Sabe qué disfruta Mamá ahora versus hace un año'),
  ('mb_page.persona2_b3', 'es', 'Puede intervenir y ayudar con confianza desde el primer día'),
  ('mb_page.persona3_title', 'es', 'El cuidador principal'),
  ('mb_page.persona3_quote', 'es', '"Yo soy el banco de memoria. El Libro de Memoria significa que no tengo que explicar todo cada vez."'),
  ('mb_page.persona3_b1', 'es', 'Documenta todo una vez — no una docena de veces'),
  ('mb_page.persona3_b2', 'es', 'Comparte la carga del cuidado sin perder el control de la precisión'),
  ('mb_page.persona3_b3', 'es', 'Reduce la carga emocional de la comunicación constante'),
  ('mb_page.persona4_title', 'es', 'El médico de cabecera o enfermero comunitario'),
  ('mb_page.persona4_quote', 'es', '"Las familias que llegan organizadas nos ayudan a brindar mejor atención."'),
  ('mb_page.persona4_b1', 'es', 'Los cuidadores llegan a las citas con notas médicas claras y actuales'),
  ('mb_page.persona4_b2', 'es', 'Las alergias y condiciones están documentadas, no adivinadas'),
  ('mb_page.persona4_b3', 'es', 'Los contactos están disponibles para conversaciones de cuidado coordinadas'),
  ('mb_page.faq_title', 'es', 'Preguntas Frecuentes'),
  ('mb_page.faq_subtitle', 'es', 'Preguntas comunes sobre la función Libro de Memoria.'),
  ('mb_page.faq1_q', 'es', '¿Qué es el Libro de Memoria y quién puede verlo?'),
  ('mb_page.faq1_a', 'es', 'El Libro de Memoria es un perfil de cuidado estructurado para su ser querido, que cubre identidad, contactos, contexto médico y preferencias personales. Es parte de su plan Family Circle de CarerView. El propietario del equipo lo crea y actualiza. Cada miembro del equipo que invite puede ver el Libro de Memoria completo tan pronto como se una — no se requiere configuración adicional.'),
  ('mb_page.faq2_q', 'es', '¿Necesito el plan Family Circle para usar el Libro de Memoria?'),
  ('mb_page.faq2_a', 'es', 'Sí. El Libro de Memoria es una función de equipo disponible en el plan Family Circle. Está diseñado para ser compartido — por lo que tiene más sentido cuando tiene al menos otro cuidador o familiar en su equipo que se beneficia de ver la misma información que usted ha registrado.'),
  ('mb_page.faq3_q', 'es', '¿Pueden los miembros del equipo editar el Libro de Memoria?'),
  ('mb_page.faq3_a', 'es', 'Actualmente, solo el propietario del equipo puede crear y editar entradas del Libro de Memoria. Todos los demás miembros del equipo tienen acceso de solo lectura. Esto garantiza que el Libro de Memoria se mantenga preciso y consistente, con una persona responsable de mantenerlo actualizado.'),
  ('mb_page.faq4_q', 'es', '¿Es el Libro de Memoria un historial médico?'),
  ('mb_page.faq4_a', 'es', 'No. El Libro de Memoria es una referencia práctica para cuidadores — no un documento clínico. Captura información que ayuda a los cuidadores a brindar atención segura, informada y personal. Para historiales médicos formales, consulte a los proveedores de atención médica de su ser querido.'),
  ('mb_page.faq5_q', 'es', '¿Qué pasa si olvido completar una sección?'),
  ('mb_page.faq5_a', 'es', 'El Libro de Memoria funciona con lo que agrega. Las secciones incompletas muestran un estado claro para que el propietario del equipo sepa lo que aún se necesita. Puede construirlo gradualmente — incluso un Libro de Memoria parcialmente completado proporciona un valor significativo a los cuidadores entrantes.'),
  ('mb_page.faq6_q', 'es', '¿Es privada y segura la información de mi ser querido?'),
  ('mb_page.faq6_a', 'es', 'Sí. El Libro de Memoria solo es visible para los miembros de su equipo de cuidado — personas que usted ha invitado explícitamente. Se almacena de forma segura en infraestructura cifrada. CarerView nunca comparte sus datos con terceros y usted retiene la propiedad total de toda la información que ingresa.'),
  ('mb_page.faq7_q', 'es', '¿Crecerá el Libro de Memoria con el tiempo?'),
  ('mb_page.faq7_a', 'es', 'Sí. El Libro de Memoria actual cubre las cuatro secciones principales: Identidad, Contactos, Médico y Preferencias. Las actualizaciones futuras agregarán rutinas de Vida Diaria, Comidas, Actividades, una sección de Comportamiento y Seguridad, un Diario personal y un Registro de Cambios. Las entradas existentes se conservan en todas las actualizaciones.'),
  ('mb_page.cta_title', 'es', 'Comience a crear el Libro de Memoria de su ser querido hoy'),
  ('mb_page.cta_body', 'es', 'Cree una cuenta gratuita y explore CarerView — o actualice al plan Family Circle para desbloquear el Libro de Memoria y compartirlo con su equipo de cuidado.')
